// Function to make a payment via Stripe API
async function makePayment(request) {
  const headers = {
    'Authorization': `Bearer ${STRIPE_API_KEY}`,
    'Content-Type': 'application/x-www-form-urlencoded'
  };
  const response = await fetch(`${STRIPE_API_URL}/charges`, {
    method: 'POST',
    headers: headers,
    body: await request.text()
  });

  if (!response.ok) {
    throw new Error(`Stripe error: ${response.status}`);
  }
}

